// PDS Preview Page Script
// Downloads employee data, fills the Excel template, and triggers download of the filled PDS form
$(document).ready(function () {


    $(".btn-dl").on("click", async function () {
        try {
            const templateUrl = PDS_CONFIG.templateUrl;
            const apiUrl = `${PDS_CONFIG.apiBase}/employee-data`;

            /* ── 1. fetch employee PDS data ────────────────────────────────── */
            const res = await fetch(apiUrl);
            const json = await res.json();

            if (!json.success) {
                alert("Failed to load employee data");
                return;
            }

            const cells = json.cells;

            /* ── 2. load excel template ────────────────────────────────────── */
            const template = await fetch(templateUrl);
            const buffer = await template.arrayBuffer();

            const workbook = new ExcelJS.Workbook();
            await workbook.xlsx.load(buffer);

            /* ── 3. write raw cell values ─────── */
            Object.entries(cells).forEach(([key, cell]) => {
                const colonIdx = key.indexOf(":");
                if (colonIdx === -1) return;
                const sheetName = key.substring(0, colonIdx);
                const address = key.substring(colonIdx + 1);

                // ✅ Skip pseudo-keys (non-cell markers like __dual_country__)
                if (address.startsWith('__')) return;

                // ✅ Skip range addresses — ExcelJS only accepts single-cell refs
                if (/[A-Za-z]+\d+:[A-Za-z]+\d+/.test(address)) return;

                const sheet = workbook.getWorksheet(sheetName);
                if (!sheet) return;

                try {
                    sheet.getCell(address).value = cell.v ?? "";
                } catch (e) {
                    console.warn(`[PDS] Skipped cell ${key}:`, e.message);
                }
            });

            /* ── 4a. Collect values ─────── */
            // ... (your existing bySheet / groupBySheet code) ...
            var bySheet = groupBySheet(cells);
            var c1 = bySheet["C1"] || {};

            // Extract checkbox values (your existing logic) ...

            /* ── 4b. Build formatted strings ─────── */
            // ... (your existing buildCheckboxText calls) ...

            /* ── 4c. Write checkbox cells ─────── */
            // ... (your existing CHECKBOX_CELL_MAP) ...

            // ✅ FIX: Write dual citizenship country to J15 (the blank cell right of "Pls. indicate country:")


            /* ── 4d. Dual citizenship country → J16:N16 ───────────────────── */
            const dualCountryEntry = cells["C1:__dual_country__"];
            const dualCountryVal = (dualCountryEntry?.v ?? "").toString().trim();

            const sheetC1 = workbook.getWorksheet("C1");
            if (sheetC1) {
                try { sheetC1.unMergeCells("J16:N16"); } catch (e) { }
                sheetC1.mergeCells("J16:N16");

                const countryCell = sheetC1.getCell("J16");
                countryCell.value = dualCountryVal || "";
                countryCell.font = { name: "Arial Narrow", size: 8, bold: true };
                countryCell.alignment = {
                    horizontal: "center",
                    vertical: "middle",
                    wrapText: false
                };

                // ✅ Full border restoration for J16:N16
                countryCell.border = {
                    top: INNER_BORDER,
                    bottom: OUTER_BORDER,   // bottom outer border of citizenship block
                    left: INNER_BORDER,
                    right: OUTER_BORDER    // right outer border — must connect with rows above
                };
            }
            /* ── 4. CHECKBOX PASS: rewrite checkbox cells ──────────────────── *
             *
             * Helper: build a display string like  "☑ Male  ☐ Female"
             * from an array of option labels and the currently selected value.
             *
             * selected  – the raw string from the API (lowercase-compared)
             * options   – array of { label: string, match: string }
             * separator – string between options (default two spaces)
             */
            function buildCheckboxText(selected, options, separator) {
                separator = separator || "   ";
                var val = (selected || "").toString().toLowerCase().trim();
                return options.map(function (opt) {
                    var ticked = val === opt.match.toLowerCase();
                    return (ticked ? "\u2611" : "\u2610") + " " + opt.label;
                }).join(separator);
            }

            /* ── 4a. Collect the values we need from the raw cells object ──── */
            // Group cells by sheet for easy lookup
            function groupBySheet(rawCells) {
                var out = {};
                Object.entries(rawCells).forEach(function ([key, data]) {
                    var colon = key.indexOf(":");
                    if (colon === -1) return;
                    var sheet = key.substring(0, colon);
                    var addr = key.substring(colon + 1);
                    if (!out[sheet]) out[sheet] = {};
                    out[sheet][addr] = data;
                });
                return out;
            }

            var bySheet = groupBySheet(cells);
            var c1 = bySheet["C1"] || {};

            // Walk every C1 cell and sniff the checkbox values (same logic as
            // extractVals in pds_renderer.js so both places stay in sync).
            var sexVal = "";
            var civilVal = "";
            var citizenVal = "";
            var dualTypeVal = "";

            Object.values(c1).forEach(function (data) {
                var raw = ((data && data.v !== undefined) ? data.v : (data || ""))
                    .toString().trim().toLowerCase();

                if (!sexVal && /^(male|female)$/.test(raw))
                    sexVal = raw;

                if (!civilVal && /^(single|married|widowed|separated)$/.test(raw))
                    civilVal = raw;
                if (!civilVal && /^other/.test(raw))
                    civilVal = "other";

                if (!citizenVal && raw === "filipino")
                    citizenVal = "filipino";
                if (!citizenVal && /^dual/.test(raw))
                    citizenVal = "dual citizenship";

                if (!dualTypeVal && raw === "by birth")
                    dualTypeVal = "by birth";
                if (!dualTypeVal && /^by naturalization/.test(raw))
                    dualTypeVal = "by naturalization";
            });

            /* ── 4b. Build the formatted strings ──────────────────────────── */
            var sexText = buildCheckboxText(sexVal, [
                { label: "Male", match: "male" },
                { label: "Female", match: "female" }
            ]);

            var civilText = buildCheckboxText(civilVal, [
                { label: "Single", match: "single" },
                { label: "Married", match: "married" },
                { label: "Widowed", match: "widowed" },
                { label: "Separated", match: "separated" },
                { label: "Other/s:", match: "other" }
            ]);

            var citizenText = buildCheckboxText(citizenVal, [
                { label: "Filipino", match: "filipino" },
                { label: "Dual Citizenship", match: "dual citizenship" }
            ]);

            // Dual-type boxes only make sense when citizenship is Dual; otherwise
            // render them as empty boxes so the printed form is still correct.
            var dualTypeText = buildCheckboxText(
                citizenVal === "dual citizenship" ? dualTypeVal : "",
                [
                    { label: "By Birth", match: "by birth" },
                    { label: "By Naturalization", match: "by naturalization" }
                ]
            );

            /* ── 4c. Write into the template ───────────────────────────────── *
             *
             * IMPORTANT: adjust these Excel addresses to match your actual
             * template.  The values below match the layout visible in the
             * screenshot (CS Form 212, Revised 2025, Sheet C1).
             *
             *   F16  → SEX AT BIRTH value cell
             *   F17  → CIVIL STATUS value cell
             *   J13  → CITIZENSHIP value cell  (same row as "16. CITIZENSHIP")
             *   J14  → By Birth / By Naturalization sub-cell
             */
            /* ── 4c. Write into the template ───────────────────────────────── */
            var CHECKBOX_CELL_MAP = {
                sex: ["C1", "F16", sexText],
                civil: ["C1", "F17", civilText],
                citizenship: ["C1", "J13", citizenText],
                dualType: ["C1", "J14", dualTypeText]
            };

            // Border styles matching the template
            var OUTER_BORDER = { style: "medium", color: { argb: "FF555555" } };  // 2px #555
            var INNER_BORDER = { style: "thin", color: { argb: "FFaaaaaa" } };  // 1px #aaa

            // Full border spec per merged cell address
            var BORDER_MAP = {
                "J13": {
                    top: OUTER_BORDER,   // top outer border of citizenship block
                    bottom: INNER_BORDER,
                    left: INNER_BORDER,
                    right: OUTER_BORDER    // RIGHT outer border — the one that was missing
                },
                "J14": {
                    top: INNER_BORDER,
                    bottom: INNER_BORDER,
                    left: INNER_BORDER,
                    right: OUTER_BORDER
                }
            };

            Object.values(CHECKBOX_CELL_MAP).forEach(function ([sheetName, addr, text]) {
                var sheet = workbook.getWorksheet(sheetName);
                if (!sheet) return;

                // Unmerge then re-merge to ensure full J-to-N span
                var mergeMap = { "J14": "J14:N14", "J13": "J13:N13" };
                if (mergeMap[addr]) {
                    try { sheet.unMergeCells(mergeMap[addr]); } catch (e) { }
                    sheet.mergeCells(mergeMap[addr]);
                }

                var cell = sheet.getCell(addr);
                cell.value = text;

                cell.font = Object.assign({}, cell.font, {
                    name: "Arial Narrow",
                    size: addr === "J14" ? 7 : 8
                });

                cell.alignment = Object.assign({}, cell.alignment || {}, {
                    horizontal: "left",
                    vertical: "middle",
                    wrapText: true
                });

                // ✅ Restore full border (all 4 sides) — right border was the missing one
                if (BORDER_MAP[addr]) {
                    cell.border = BORDER_MAP[addr];
                }
            });
            
            

            // Helper: apply a thick right border to the last cell of a merged range
            function applyRightBorder(sheet, cellAddr, thick) {
                var cell = sheet.getCell(cellAddr);
                var borderStyle = thick ? "medium" : "thin";
                cell.border = Object.assign({}, cell.border || {}, {
                    right: { style: borderStyle, color: { argb: "FF555555" } }
                });
            }

            Object.values(CHECKBOX_CELL_MAP).forEach(function ([sheetName, addr, text]) {
                var sheet = workbook.getWorksheet(sheetName);
                if (!sheet) return;

                // Unmerge then re-merge to ensure full span
                var mergeMap = { "J14": "J14:N14", "J13": "J13:N13" };
                if (mergeMap[addr]) {
                    try { sheet.unMergeCells(mergeMap[addr]); } catch (e) { }
                    sheet.mergeCells(mergeMap[addr]);
                }

                var cell = sheet.getCell(addr);
                cell.value = text;

                cell.font = Object.assign({}, cell.font, {
                    name: "Arial Narrow",
                    size: addr === "J14" ? 7 : 8
                });

                cell.alignment = Object.assign({}, cell.alignment || {}, {
                    horizontal: "left",
                    vertical: "middle",
                    wrapText: true
                });

                // ✅ Restore right border lost during merge — use "medium" to match template's 2px solid border
                cell.border = Object.assign({}, cell.border || {}, {
                    right: { style: "medium", color: { argb: "FF555555" } }
                });
            });

            /* ── 5. generate xlsx and trigger download (original logic) ────── */
            const out = await workbook.xlsx.writeBuffer();
            const blob = new Blob(
                [out],
                { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" }
            );

            const link = document.createElement("a");
            link.href = URL.createObjectURL(blob);

            let surname = json.cells["C1:D10"]?.v ?? "Unknown";
            surname = surname.toUpperCase().replace(/\s+/g, "_");
            link.download = `PDS_${surname}.xlsx`;

            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);

        } catch (err) {
            console.error(err);
            alert("Failed to generate PDS Excel file");
        }
    });
});

