let currentSheet = 'C1';

function switchTab(name, el) {
    document.querySelectorAll('.pds-tab').forEach(t => t.classList.remove('active'));
    el.classList.add('active');
    currentSheet = name;
    document.getElementById('sheetContent').innerHTML = SHEETS[name];
}

// Init
document.getElementById('sheetContent').innerHTML = SHEETS['C1'];

/**
* fetch_pds_data.js
* Fetches employee PDS data from the API and fills the HTML table cells.
* Mirrors the $.getJSON pattern used in personalInfoForm.
*
* Depends on: PDS_CONFIG.apiBase (injected by PHP view)
* Must be loaded AFTER the tab HTML is already in the DOM.
*/

$(document).ready(function () {

    /**
     * Build a logical grid map from a <table> element.
     * Returns object: { "row,col": td_element, ... }
     * Accounts for rowspan and colspan.
     */
    function buildGridMap(tableEl) {
        var map = {};
        var occupied = {}; // tracks cells already claimed by rowspan/colspan

        var rows = tableEl.rows;
        for (var r = 0; r < rows.length; r++) {
            var colCursor = 1;
            var cells = rows[r].cells;
            for (var c = 0; c < cells.length; c++) {
                // Skip columns already occupied by a previous rowspan
                while (occupied[(r + 1) + ',' + colCursor]) colCursor++;

                var td = cells[c];
                var rs = td.rowSpan || 1;
                var cs = td.colSpan || 1;

                // Register this td at its logical position
                map[(r + 1) + ',' + colCursor] = td;

                // Mark all cells spanned by this td as occupied
                for (var dr = 0; dr < rs; dr++) {
                    for (var dc = 0; dc < cs; dc++) {
                        if (dr === 0 && dc === 0) continue;
                        occupied[(r + 1 + dr) + ',' + (colCursor + dc)] = true;
                    }
                }

                colCursor += cs;
            }
        }
        return map;
    }

    /**
     * Convert column letter(s) to 1-based index.
     * A=1, B=2, ..., Z=26, AA=27, etc.
     */
    function colToIndex(letters) {
        return letters.toUpperCase().split('').reduce(function (acc, ch) {
            return acc * 26 + (ch.charCodeAt(0) - 64);
        }, 0);
    }

    /**
     * Parse "D10" → { row: 10, col: 4 }
     */
    function parseCell(addr) {
        var m = String(addr).match(/^([A-Za-z]+)(\d+)$/);
        if (!m) return null;
        return { col: colToIndex(m[1]), row: parseInt(m[2], 10) };
    }

    /**
     * Apply cells for a single sheet tab.
     * sheetName: e.g. "C1"
     * sheetCells: { "D10": { v: "DELA CRUZ" }, "D11": { v: "JUAN" }, ... }
     */
    function applySheetData(sheetName, sheetCells) {
        var tableEl = document.getElementById('sheet-' + sheetName);
        if (!tableEl) return;

        var gridMap = buildGridMap(tableEl);

        $.each(sheetCells, function (addr, data) {
            var value = (data && data.v !== undefined) ? data.v : data;
            if (value === null || value === undefined || value === '') return;

            var rc = parseCell(addr);
            if (!rc) return;

            var key = rc.row + ',' + rc.col;
            var td = gridMap[key];
            if (!td) return;

            // Write value and highlight
            $(td).text(String(value)).addClass('pds-filled');
        });
    }

    /**
     * Group flat cells object by sheet name.
     * Input:  { "C1:D10": { v: "DELA CRUZ" }, "C2:A5": { v: "Engineer" } }
     * Output: { "C1": { "D10": { v: "DELA CRUZ" } }, "C2": { "A5": { v: "Engineer" } } }
     */
    function groupBySheet(cells) {
        var grouped = {};
        $.each(cells, function (key, data) {
            var colon = key.indexOf(':');
            if (colon === -1) return;
            var sheet = key.substring(0, colon);
            var addr = key.substring(colon + 1);
            if (!grouped[sheet]) grouped[sheet] = {};
            grouped[sheet][addr] = data;
        });
        return grouped;
    }

    /* ─────────────────────────────────────────────────────────────
       MAIN: Fetch employee data then apply to all visible sheets
    ───────────────────────────────────────────────────────────── */
    var apiUrl = PDS_CONFIG.apiBase + '/employee-data';

    $.getJSON(apiUrl, function (res) {
        if (!res.success || !res.cells) {
            console.warn('[PDS] API returned no cells:', res);
            return;
        }

        var allCells = res.cells;
        var bySheet = groupBySheet(allCells);

        // Store globally so tab switches can re-apply
        window._pdsCellsBySheet = bySheet;

        // Apply to whichever sheet tab is currently visible (C1 on load)
        $.each(bySheet, function (sheetName, sheetCells) {
            applySheetData(sheetName, sheetCells);
        });

        console.log('[PDS] Filled', Object.keys(allCells).length, 'cells from API.');

    }).fail(function (jqXHR, textStatus, errorThrown) {
        console.error('[PDS] Failed to load employee data:', textStatus, errorThrown);
    });

    /* ─────────────────────────────────────────────────────────────
       Re-apply data after every tab switch.
       Hooks into the global switchTab() defined in the view.
    ───────────────────────────────────────────────────────────── */
    var _originalSwitchTab = window.switchTab;

    window.switchTab = function (sheetName, el) {
        // Let the original switcher render the HTML first
        if (typeof _originalSwitchTab === 'function') {
            _originalSwitchTab(sheetName, el);
        }

        // Re-apply employee data to the freshly rendered table
        if (window._pdsCellsBySheet && window._pdsCellsBySheet[sheetName]) {
            applySheetData(sheetName, window._pdsCellsBySheet[sheetName]);
        }
    };

});